/**
 * Pages Adapter
 * Category: internal
 */
declare function createPagesAdapter(sdk: MirraSDK): {
    /**
     * Create a new page with JSX code. The code is compiled to HTML with React, Tailwind CSS, Recharts, and Lucide icons available as globals. Define a top-level `function App()` component as the entry point. Do NOT use import/require statements — all libraries are pre-loaded via CDN. Use Recharts components directly (e.g. `<BarChart>`, `<ResponsiveContainer>`) and Lucide icons via `lucide.IconName`. STYLE — Every page includes the Mirra design system with pre-configured Tailwind theme. Use semantic theme tokens for automatic dark/light support: - Backgrounds: bg-m-bg (page), bg-m-surface (cards), bg-m-surface-alt (nested elements) - Text: text-m-text (primary), text-m-text-secondary, text-m-text-muted - Borders: border-m-border - Accent: text-m-accent-text, bg-m-accent, bg-m-accent-soft - Brand purple scale: bg-mirra-50 through bg-mirra-950 - Fonts: font-display (Syne — headings), font-body (Inter — content), font-mono (numbers/data) - Charts: use MIRRA_COLORS array for fills/strokes (8 brand-derived colors) Dark mode is the default. For light pages, add data-theme="light" to the root wrapper div. DO: Use generous padding (p-8 md:p-12), consistent gaps (gap-4 gap-6), subtle borders (border border-m-border) over heavy shadows, font-mono for numbers/stats, the m-* theme tokens for all colors. DO NOT: Use emoji as bullet points, add hover:scale on cards, use bg-slate/bg-gray (use m-* tokens), use multiple flashy gradients.
     * @param args.path - URL path for the page (e.g. "/dashboard"). Must start with /, lowercase alphanumeric and hyphens only, 2-50 chars.
     * @param args.title - Display title for the page
     * @param args.code - JSX source code. Must define a top-level function App() component. Do NOT use import/require — React, ReactDOM, Recharts (BarChart, PieChart, LineChart, ResponsiveContainer, etc.), lucide-react, Tailwind CSS, and the Mirra design system (m-* color tokens, font-display/font-body/font-mono, MIRRA_COLORS array) are all pre-loaded globals.
     * @param args.description - Optional description of the page (optional)
     * @param args.visibility - Page visibility: "private" (default) or "public" (optional)
     */
    createPage: (args: PagesCreatePageArgs) => Promise<any>;
    /**
     * Create a report page using the widget factory. Instead of writing JSX code, specify a structured widget spec and the system generates optimized JSX deterministically. Supports 11 widget types: stat-grid, bar-chart, line-chart, area-chart, pie-chart, table, list, metric-card, text-block, treemap, radar-chart. Each widget fetches data from a Data collection at runtime.
     * @param args.path - URL path for the page (e.g. "/sales-report"). Must start with /, lowercase alphanumeric and hyphens only.
     * @param args.title - Display title for the report page
     * @param args.description - Optional subtitle displayed below the title (optional)
     * @param args.theme - Color theme: "dark" (default) or "light" (optional)
     * @param args.layout - Layout: "dashboard" (2-col grid, default), "report" (single-col max-w-4xl), "single-column" (full-width single-col) (optional)
     * @param args.visibility - Page visibility: "private" (default) or "public" (optional)
     * @param args.widgets - Array of widget specs. Each widget has: type (string), collection (Data collection slug), transform (optional: { type: "raw"|"groupBy"|"timeSeries", ... }), display ({ title?, height?, colorIndex? }), config (type-specific fields). Widget types and config: - stat-grid: { columns, items: [{ label, valueField, format?, aggregate? }] } - bar-chart: { xField, yField, orientation?, stacked? } - line-chart: { xField, yFields[], smooth? } - area-chart: { xField, yFields[], stacked? } - pie-chart: { labelField, valueField, donut? } - table: { columns: [{ field, label, format?, align? }], limit? } - list: { titleField, subtitleField?, metaField?, metaFormat?, limit? } - metric-card: { valueField, label, format? } - text-block: { content } - treemap: { nameField, valueField } - radar-chart: { axisField, valueFields[] } Transform types: - raw: { sort?: { field, direction }, limit? } - groupBy: { field, metric: { field, op: "sum"|"avg"|"count"|"min"|"max" }, sort?, limit? } - timeSeries: { timeField, granularity?: "day"|"week"|"month" }
     */
    createReportPage: (args: PagesCreateReportPageArgs) => Promise<any>;
    /**
     * Create or update a report page using the widget factory. If a page exists at the given path, it is updated with the new widget spec (previous version saved for rollback). If no page exists, it is created. Use this instead of createReportPage when evolving an existing report.
     * @param args.path - URL path for the page (e.g. "/agent-report-my-space"). Must start with /, lowercase alphanumeric and hyphens only.
     * @param args.title - Display title for the report page
     * @param args.description - Optional subtitle displayed below the title (optional)
     * @param args.theme - Color theme: "dark" (default) or "light" (optional)
     * @param args.layout - Layout: "dashboard" (2-col grid, default), "report" (single-col max-w-4xl), "single-column" (full-width single-col) (optional)
     * @param args.visibility - Page visibility: "private" (default) or "public" (optional)
     * @param args.widgets - Array of widget specs. Same format as createReportPage widgets.
     * @param args.updateReason - Why the page is being updated (used as version description for rollback) (optional)
     */
    upsertReportPage: (args: PagesUpsertReportPageArgs) => Promise<any>;
    /**
     * Edit a page using search-and-replace. Each edit replaces one exact match of oldCode with newCode in the current source. Much more efficient than updatePage for small changes — only send the parts that change. Use getPage first to read the current code. The old_code string must appear exactly once in the source.
     * @param args.pageId - The page ID to edit
     * @param args.edits - Array of search-and-replace edits. Each edit has oldCode (exact string to find) and newCode (replacement string). Applied sequentially.
     */
    editPage: (args: PagesEditPageArgs) => Promise<any>;
    /**
     * Replace the entire page code. Use editPage instead for small changes — it is more efficient. Only use updatePage when rewriting most of the page.
     * @param args.pageId - The page ID to update
     * @param args.code - New JSX source code (optional)
     * @param args.title - New title (optional)
     * @param args.description - New description (optional)
     */
    updatePage: (args: PagesUpdatePageArgs) => Promise<any>;
    /**
     * Revert a page to a previous version. The current code becomes a new version entry.
     * @param args.pageId - The page ID to revert
     * @param args.versionIndex - Index of the version to restore (0 = most recent saved version)
     */
    revertPage: (args: PagesRevertPageArgs) => Promise<any>;
    /**
     * Get a page by its ID or by path within the current graph. Returns page metadata and current code.
     * @param args.pageId - The page ID (optional)
     * @param args.path - The page path (e.g. "/dashboard"). Used with the current graphId. (optional)
     */
    getPage: (args: PagesGetPageArgs) => Promise<any>;
    /**
     * List all pages for the current graph. Optionally filter by status.
     * @param args.status - Filter by status: "active" (default) or "deleted" (optional)
     */
    listPages: (args: PagesListPagesArgs) => Promise<any>;
    /**
     * Soft-delete a page by setting its status to "deleted".
     * @param args.pageId - The page ID to delete
     */
    deletePage: (args: PagesDeletePageArgs) => Promise<any>;
    /**
     * Publish a page, making it publicly accessible. Generates an API key for the page.
     * @param args.pageId - The page ID to publish
     * @param args.publicCollections - Optional array of collection tags for public discovery (optional)
     */
    publishPage: (args: PagesPublishPageArgs) => Promise<any>;
    /**
     * Unpublish a page, making it private.
     * @param args.pageId - The page ID to unpublish
     */
    unpublishPage: (args: PagesUnpublishPageArgs) => Promise<any>;
    /**
     * Get the public URL for a page.
     * @param args.pageId - The page ID
     */
    getPageUrl: (args: PagesGetPageUrlArgs) => Promise<any>;
};
